#include <iostream>
#include <string>
#include <memory>
#include <vector>

// Abstract base class Animal
class Animal {
public:
    virtual void makeSound() = 0;
    virtual ~Animal() {}
};

// Concrete class Dog
class Dog : public Animal {
public:
    void makeSound() override {
        std::cout << "Woof! Woof!" << std::endl;
    }
    ~Dog() override {}
};

// Concrete class Cat
class Cat : public Animal {
public:
    void makeSound() override {
        std::cout << "Meow! Purrr." << std::endl;
    }
    ~Cat() override {}
};

int main() {
    std::vector<std::unique_ptr<Animal>> farm_animals;

    farm_animals.push_back(std::make_unique<Dog>());
    farm_animals.push_back(std::make_unique<Cat>());
    farm_animals.push_back(std::make_unique<Dog>());

    for (const auto& animal : farm_animals) {
        animal->makeSound();
    }

    std::cout << "--- Stack-allocated animals ---" << std::endl;
    Dog stack_dog;
    Cat stack_cat;
    stack_dog.makeSound();
    stack_cat.makeSound();

    return 0;
}
